"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[97564],{74844:(a,s,e)=>{e.r(s),e.d(s,{data:()=>i});const i={key:"v-5259529b",path:"/SuperMap/guid/iDeskTop%E6%93%8D%E4%BD%9C%E5%85%A5%E9%97%A8.html",title:"iDesktop操作入门",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"(一)创建文件型工作空间",slug:"一-创建文件型工作空间",children:[{level:3,title:"（1）打开iDesktop软件",slug:"_1-打开idesktop软件",children:[]},{level:3,title:"（2）创建一个工作空间文件",slug:"_2-创建一个工作空间文件",children:[]},{level:3,title:"（3）设置工作空间命名（防止文件丢失导致数据泄露）",slug:"_3-设置工作空间命名-防止文件丢失导致数据泄露",children:[]},{level:3,title:"（4）点击保存",slug:"_4-点击保存",children:[]}]},{level:2,title:"(二)绘制数据",slug:"二-绘制数据",children:[{level:3,title:"（1）创建工作空间",slug:"_1-创建工作空间",children:[]},{level:3,title:"（2）新建数据源",slug:"_2-新建数据源",children:[]},{level:3,title:"（3）新建数据集",slug:"_3-新建数据集",children:[]},{level:3,title:"（4）把数据集添加到地图",slug:"_4-把数据集添加到地图",children:[]},{level:3,title:"（5）绘制",slug:"_5-绘制",children:[]},{level:3,title:"（6）保存工作空间",slug:"_6-保存工作空间",children:[]}]},{level:2,title:"(三)属性表编辑",slug:"三-属性表编辑",children:[{level:3,title:"（1）字段编辑",slug:"_1-字段编辑",children:[]},{level:3,title:"（2）修改字段特别注意",slug:"_2-修改字段特别注意",children:[]},{level:3,title:"（3）修改属性值",slug:"_3-修改属性值",children:[]}]}],git:{updatedTime:1653445943e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"SuperMap/guid/iDeskTop操作入门.md"}},56346:(a,s,e)=>{e.r(s),e.d(s,{default:()=>t});const i=(0,e(57293).uE)('<h1 id="idesktop操作入门" tabindex="-1"><a class="header-anchor" href="#idesktop操作入门" aria-hidden="true">#</a> iDesktop操作入门</h1><h2 id="一-创建文件型工作空间" tabindex="-1"><a class="header-anchor" href="#一-创建文件型工作空间" aria-hidden="true">#</a> (一)创建文件型工作空间</h2><h3 id="_1-打开idesktop软件" tabindex="-1"><a class="header-anchor" href="#_1-打开idesktop软件" aria-hidden="true">#</a> （1）打开iDesktop软件</h3><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060910489.png" alt="在这里插入图片描述"></p><h3 id="_2-创建一个工作空间文件" tabindex="-1"><a class="header-anchor" href="#_2-创建一个工作空间文件" aria-hidden="true">#</a> （2）创建一个工作空间文件</h3><p>右键&quot;未命名工作空间-&gt;另存工作空间&quot;把工作空间存储为文档</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060910490.png" alt="在这里插入图片描述"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060910364.png" alt="在这里插入图片描述"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060910492.png" alt="在这里插入图片描述"></p><h3 id="_3-设置工作空间命名-防止文件丢失导致数据泄露" tabindex="-1"><a class="header-anchor" href="#_3-设置工作空间命名-防止文件丢失导致数据泄露" aria-hidden="true">#</a> （3）设置工作空间命名（防止文件丢失导致数据泄露）</h3><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060910493.png" alt="在这里插入图片描述"></p><h3 id="_4-点击保存" tabindex="-1"><a class="header-anchor" href="#_4-点击保存" aria-hidden="true">#</a> （4）点击保存</h3><p>可以在指定目录下看到&quot;创建工作空间.smwu&quot;文件</p><p>[TOC]</p><h2 id="二-绘制数据" tabindex="-1"><a class="header-anchor" href="#二-绘制数据" aria-hidden="true">#</a> (二)绘制数据</h2><h3 id="_1-创建工作空间" tabindex="-1"><a class="header-anchor" href="#_1-创建工作空间" aria-hidden="true">#</a> （1）创建工作空间</h3><p>按照&quot;操作入门（一）&quot;新建一个工作空间&quot;绘制数据&quot;</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912237.png" alt="1627974645156"></p><h3 id="_2-新建数据源" tabindex="-1"><a class="header-anchor" href="#_2-新建数据源" aria-hidden="true">#</a> （2）新建数据源</h3><p>右键&quot;数据源-&gt;新建文件型数据源&quot;</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912260.png" alt="1627974719534"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912323.png" alt="1627974811991"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912289.png" alt="1627974851903"></p><h3 id="_3-新建数据集" tabindex="-1"><a class="header-anchor" href="#_3-新建数据集" aria-hidden="true">#</a> （3）新建数据集</h3><p>右键&quot;数据源Test-&gt;新建数据集&quot;</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912265.png" alt="1627974958317"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912411.png" alt="1627974967561"></p><p>添加点，线，面，三个图层,坐标系选择为GCS_China_2000</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912730.png" alt="1627975081456"></p><p>点击创建</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912747.png" alt="1627975125413"></p><h3 id="_4-把数据集添加到地图" tabindex="-1"><a class="header-anchor" href="#_4-把数据集添加到地图" aria-hidden="true">#</a> （4）把数据集添加到地图</h3><p>右键数据集-&gt;添加到新地图</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912781.png" alt="1627975195599"></p><p>也可以直接双击=创建新地图（这种方式创建的地图需要ctrl+s保持后才会在管理界面中显示）</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912794.png" alt="1627975368435"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912749.png" alt="1627975453669"></p><p>剩下2个添加到当前地图</p><p>可以在图层管理器中查看当前地图的图层与图层的状态</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912765.png" alt="1627975563870"></p><h3 id="_5-绘制" tabindex="-1"><a class="header-anchor" href="#_5-绘制" aria-hidden="true">#</a> （5）绘制</h3><p>点击第三图标使之高亮表示进入编辑状态</p><p>工具栏会自动进入对象操作模块,这里都是与图形编辑相关的工具</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912254.png" alt="1627975662204"></p><p>然后我们绘制一些数据</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912237.png" alt="1627975780401"></p><h3 id="_6-保存工作空间" tabindex="-1"><a class="header-anchor" href="#_6-保存工作空间" aria-hidden="true">#</a> （6）保存工作空间</h3><h2 id="三-属性表编辑" tabindex="-1"><a class="header-anchor" href="#三-属性表编辑" aria-hidden="true">#</a> (三)属性表编辑</h2><p>这里只是简单介绍下，详细说明可以看《SuperMap iDesktop基础教程》第6章，里面介绍的非常详细</p><h3 id="_1-字段编辑" tabindex="-1"><a class="header-anchor" href="#_1-字段编辑" aria-hidden="true">#</a> （1）字段编辑</h3><p>右键&quot;数据集-&gt;属性&quot;，在右侧属性出口打开属性表选项卡</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912737.png" alt="1627976497988"></p><p>在这个界面可以对字段进行“添加”，“删除”，“修改”，“排序”</p><p><strong>字段名称</strong></p><p>字段名称是字段的名字。其中，以Sm开头的，是系统字段。Sm前有<em>的， 表示使用隐藏系统字段功能时，可以进行隐藏。不带</em>的可以通过隐藏列的功能 进行隐藏，同样，带*的也可以使用这种方法进行隐藏。</p><p><strong>别名</strong></p><p>字段别名是在属性表中显示的名字。它能更加简明易懂地描述字段内容。 与字段名称不同，别名不需要遵守数据库的限制，因此它们可以包含特殊字符。 通过指定别名，可以为字段提供比其实际字段名更具描述性的名称。</p><p><strong>字段类型、长度</strong></p><p>新建立属性字段后，我们可以根据字段内容进行选择字段的类型，是整形， 还是单精度型，还是文本等。长度是根据字段的类型进行设置的。</p><p><strong>缺省值</strong></p><p>新建立字段后，如果没有录入属性内容，默认值是什么，这个就是缺省值。</p><p><strong>必填</strong></p><p>必填表示该项内容是否可以为空。如果选择不为空，那么缺省值一定要进 行设置，默认为0。</p><h3 id="_2-修改字段特别注意" tabindex="-1"><a class="header-anchor" href="#_2-修改字段特别注意" aria-hidden="true">#</a> （2）修改字段特别注意</h3><p>修改已有字段时，除了修改<code>别名</code>软件会自动执行删除并创建操作，原数据集会自定建立一个备份</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912656.png" alt="1627976868831"></p><h3 id="_3-修改属性值" tabindex="-1"><a class="header-anchor" href="#_3-修改属性值" aria-hidden="true">#</a> （3）修改属性值</h3><p>右键“数据集-&gt;浏览属性表”打开属性表</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912739.png" alt="1627976965181"></p><p>双击单元格-&gt;右下角出现小黑点表示进入编辑</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912580.png" alt="1627977017979"></p><p>右键&quot;列名-&gt;更新列&quot;可以批量修改属性</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912626.png" alt="1627977071324"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912674.png" alt="1627977116927"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205060912880.png" alt="1627977127932"></p>',75),p={},t=(0,e(63243).Z)(p,[["render",function(a,s){return i}]])},63243:(a,s)=>{s.Z=(a,s)=>{const e=a.__vccOpts||a;for(const[a,i]of s)e[a]=i;return e}}}]);